import { Component, EventEmitter, Input, Output } from '@angular/core';

@Component({
  selector: 'app-star-rating',
  standalone: true,
  template: `
    <div class="stars" role="radiogroup" aria-label="Star rating">
      @for (star of stars; track star) {
        <button
        type="button"
        class="star"
        [class.filled]="star <= rating"
        (click)="onRate(star)"
        [attr.aria-label]="star + ' out of ' + max"
        [attr.aria-pressed]="star <= rating"
      >
        ★
        </button>
      }
    </div>
  `,
  styles: [
    `:host{display:inline-flex;}`,
    `.stars{display:inline-flex;gap:4px;}`,
    `.star{background:transparent;border:none;font-size:28px;cursor:pointer;padding:4px;line-height:1;color:#4b5563;transition:transform .1s ease,color .1s ease;}`,
    `.star.filled{color:#facc15;}`,
    `.star:focus-visible{outline:2px solid #facc15;outline-offset:2px;}`,
    `.star:hover{transform:scale(1.1);}`
  ]
})
export class StarRatingComponent {
  @Input() max = 5;
  @Input() rating = 0;
  @Output() ratingChange = new EventEmitter<number>();

  get stars(): number[] {
    return Array.from({ length: this.max }, (_, i) => i + 1);
  }

  onRate(value: number): void {
    if (value < 1 || value > this.max) {
      return;
    }
    this.rating = value;
    this.ratingChange.emit(this.rating);
  }
}

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [StarRatingComponent],
  template: `
    <main style="min-height:100vh; background:#0a0a0a; color:#e5e7eb; display:grid; place-items:center; padding:24px;">
      <section style="width:100%; max-width:420px; display:grid; gap:16px;">
        <h1 style="margin:0; font-size:20px; font-weight:700;">Star Rating Widget</h1>
        <div class="panel">
          <app-star-rating [(rating)]="currentRating"></app-star-rating>
          <p class="hint">Current rating: {{ currentRating }} / 5</p>
        </div>
      </section>
    </main>
  `,
  styles: [
    `.panel{background:#0b1020;border:1px solid #1f2937;border-radius:12px;padding:16px;display:grid;gap:12px;}`,
    `.hint{margin:0;font-size:14px;color:#9ca3af;}`
  ]
})
export class AppComponent {
  currentRating = 0;
}
